DROP TABLE IF EXISTS `trip_user`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `trip_user` (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `username` varchar(50) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '登录用户名',
  `password_hash` varchar(64) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '密码哈希',
  `password_salt` varchar(32) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '密码盐值',
  `nickname` varchar(50) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '显示昵称',
  `role` tinyint(1) NOT NULL DEFAULT '0' COMMENT '角色：0-普通用户, 1-管理员',
  `status` tinyint(1) NOT NULL DEFAULT '1' COMMENT '状态：1-正常, 0-冻结封禁',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `avatar` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `gender` tinyint DEFAULT NULL COMMENT '0-未知, 1-男, 2-女',
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_trip_user_username` (`username`)
) ENGINE=InnoDB AUTO_INCREMENT=9 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='系统用户表';
/*!40101 SET character_set_client = @saved_cs_client */;

