DROP TABLE IF EXISTS `poi`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `poi` (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `name` varchar(100) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'POI名称',
  `category` varchar(50) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '分类',
  `district` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '所属行政区',
  `address` varchar(200) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '具体地址',
  `latitude` decimal(10,6) DEFAULT NULL COMMENT '纬度',
  `longitude` decimal(10,6) DEFAULT NULL COMMENT '经度',
  `open_time` time DEFAULT NULL COMMENT '开放时间',
  `close_time` time DEFAULT NULL COMMENT '关闭时间',
  `closed_weekdays` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `temporarily_closed` tinyint(1) NOT NULL DEFAULT '0',
  `status_note` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `status_source` varchar(50) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'seed',
  `status_updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `avg_cost` decimal(10,2) DEFAULT '0.00' COMMENT '预计人均消费',
  `stay_duration` int NOT NULL COMMENT '建议停留时长(分钟)',
  `indoor` tinyint(1) DEFAULT '0' COMMENT '1室内 0室外',
  `night_available` tinyint(1) DEFAULT '0' COMMENT '1夜游 0否',
  `rain_friendly` tinyint(1) DEFAULT '0' COMMENT '1雨天友好 0否',
  `walking_level` varchar(20) COLLATE utf8mb4_unicode_ci DEFAULT '中' COMMENT '低/中/高',
  `tags` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '偏好标签',
  `suitable_for` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '适用群体',
  `description` text COLLATE utf8mb4_unicode_ci COMMENT '简介',
  `priority_score` decimal(4,2) DEFAULT '3.00' COMMENT '系统默认权重分数',
  `crowd_penalty` decimal(6,2) DEFAULT '0.00',
  `created_at` datetime DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  `created_by` bigint DEFAULT NULL,
  `updated_by` bigint DEFAULT NULL,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=27 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='POI综合表';
/*!40101 SET character_set_client = @saved_cs_client */;

LOCK TABLES `poi` WRITE;
/*!40000 ALTER TABLE `poi` DISABLE KEYS */;
