  `share_note` varchar(300) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `favorited` tinyint(1) NOT NULL DEFAULT '0',
  `favorite_time` datetime DEFAULT NULL,
  `is_public` tinyint(1) NOT NULL DEFAULT '0',
  `node_count` int NOT NULL DEFAULT '0',
  `total_duration` int DEFAULT NULL,
  `total_cost` decimal(10,2) DEFAULT NULL,
  `route_signature` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  `is_favorite` tinyint(1) NOT NULL DEFAULT '0',
  `is_history` tinyint(1) NOT NULL DEFAULT '1',
  `source_page` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '生成来源页面标识',
  PRIMARY KEY (`id`),
  KEY `idx_saved_itinerary_user` (`user_id`)
) ENGINE=InnoDB AUTO_INCREMENT=46 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='Saved itinerary snapshots';
